from flask import Flask, request, jsonify
import redis

app = Flask(__name__)

# Configure Redis connection
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0)

# Allowlist of safe Redis commands
safe_commands = {
    'GET': lambda args: redis_client.get(args[0]),
    'SET': lambda args: redis_client.set(args[0], args[1]),
    'DEL': lambda args: redis_client.delete(*args),
    # Add more safe commands as needed
}

@app.route('/execute', methods=['GET'])
def execute_command():
    command = request.args.get('command')
    if not command:
        return jsonify({'error': 'No command provided'}), 400

    parts = command.split()
    cmd = parts[0].upper()
    args = parts[1:]

    if cmd in safe_commands:
        try:
            result = safe_commands[cmd](args)
            return jsonify({'result': result})
        except Exception as e:
            return jsonify({'error': str(e)}), 500
    else:
        return jsonify({'error': 'Command not allowed'}), 403

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0')